--
-- Name: chart; Type: VIEW; Schema: public; Owner: ksn38
--

CREATE VIEW public.chart AS
 SELECT DISTINCT b.id,
    a.name,
    (((b.val - a.aval) * 100) / a.aval) AS cnd_val,
    (((b.val_noexp - a.aval_noexp) * 100) / a.aval_noexp) AS cnd_vn,
    ((((b.res_vac - (a.ares_vac)::double precision) * (100)::double precision) / (a.ares_vac)::double precision))::integer AS cnd_rv
   FROM (public.mean a
     LEFT JOIN public.langs b ON (((a.name)::text = (b.name)::text)))
  WHERE (b.date_added = CURRENT_DATE)
  ORDER BY (((b.val - a.aval) * 100) / a.aval) DESC;


